use fastly::http::{header, Method, StatusCode};
use fastly::{Error, Request, Response};

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    
    let backend_name = match path {
        p if p.starts_with("/api/") => "api_backend",
        p if p.starts_with("/images/") => "images_backend",
        p if p.starts_with("/static/") => "static_backend",
        _ => "default_backend",
    };
    
    req.set_pass(true);
    
    let mut beresp = req.send(backend_name)?;
    
    beresp.set_header(header::SERVER, "Fastly-Compute-Router");
    
    Ok(beresp)
}